import{_ as t,o,c as r,ag as n}from"./chunks/framework.CAXxHpAX.js";const p=JSON.parse('{"title":"Brand","description":"","frontmatter":{},"headers":[],"relativePath":"brand.md","filePath":"brand.md","lastUpdated":1777888460000}'),a={name:"brand.md"};function s(i,e,d,c,h,l){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="brand" tabindex="-1">Brand <a class="header-anchor" href="#brand" aria-label="Permalink to &quot;Brand&quot;">​</a></h1><p><strong>Date locked:</strong> 2026-05-03 (rename baseline) <strong>Decision reference:</strong> <code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code> + <code>docs/superpowers/research/2026-05-03-zkqes-rename-analysis.md</code></p><p>A one-page reference for anyone writing public-facing copy, talks, slides, or third-party documentation about this project. Read once; carry forward.</p><h2 id="name" tabindex="-1">Name <a class="header-anchor" href="#name" aria-label="Permalink to &quot;Name&quot;">​</a></h2><p><strong><code>zkqes</code></strong> — lowercase noun, no expansion needed in casual use. Matches the domain (<code>zkqes.org</code>) and the descriptor.</p><p>When introducing the project to an outside reader who&#39;s seeing it for the first time, the two-second descriptor is <strong>&quot;a zero-knowledge proof of a qualified electronic signature&quot;</strong> (the literal expansion of zk-QES, eIDAS-aware audiences will recognize it). After the first use, just <code>zkqes</code>.</p><p>There is no protocol-vs-project-vs-descriptor split. The repo, the protocol, the website, the package scope, the CLI binary, the contract namespace — all named <code>zkqes</code>. One name, one thing.</p><h2 id="what-this-brand-reversed" tabindex="-1">What this brand REVERSED <a class="header-anchor" href="#what-this-brand-reversed" aria-label="Permalink to &quot;What this brand REVERSED&quot;">​</a></h2><p>The 2026-05-03 morning lock briefly used a three-tier hierarchy: <code>QKB</code> (protocol noun, structurally locked), <code>zk-QES</code> (descriptor), <code>Identity Escrow</code> (project umbrella). That decision was reversed the same day, on the explicit reasoning that:</p><ul><li>Nothing was actually shipped under the QKB name yet (zero npm publishes, zero contracts deployed, zero ceremony rounds run).</li><li>The three-name split was confusing for a single-thing project.</li><li>The cost of renaming was strictly minimal at this point in the lifecycle.</li></ul><p>So the structural rename to a single noun happened before any of those names left the repo. Future readers seeing this section can ignore the prior brand split entirely; it never reached production.</p><h2 id="how-to-write-about-the-project" tabindex="-1">How to write about the project <a class="header-anchor" href="#how-to-write-about-the-project" aria-label="Permalink to &quot;How to write about the project&quot;">​</a></h2><p><strong>Do:</strong></p><ul><li>Lead with the single name: &quot;zkqes is a zero-knowledge protocol over qualified electronic signatures.&quot;</li><li>Use <code>zkqes</code> in install commands, code references, contract addresses, ceremony command paths.</li><li>When invoking an outside reader, expand to &quot;a zero-knowledge proof of a qualified electronic signature (zk-QES)&quot; once at first introduction, then drop the expansion.</li></ul><p><strong>Don&#39;t:</strong></p><ul><li>Don&#39;t introduce additional names, sub-brands, or umbrella terms.</li><li>Don&#39;t reintroduce &quot;QKB&quot;, &quot;Qualified Key Binding&quot;, &quot;Identity Escrow&quot;, &quot;QIE&quot;, or &quot;Qualified Identity Escrow&quot; anywhere in public-facing copy. (The 9 frozen consensus byte strings inside the protocol — see invariant below — are not branding; they&#39;re protocol-internal hash inputs that predate the rename.)</li><li>Don&#39;t expand <code>zkqes</code> in headlines or branding except as one-shot context.</li></ul><h2 id="frozen-consensus-bytes-not-branding" tabindex="-1">Frozen consensus bytes (NOT branding) <a class="header-anchor" href="#frozen-consensus-bytes-not-branding" aria-label="Permalink to &quot;Frozen consensus bytes (NOT branding)&quot;">​</a></h2><p>A small set of string literals inside the codebase begin with <code>qkb-</code> and look like brand artifacts but are NOT branding. They are protocol-internal byte strings hashed (keccak256 / SHA-256 / Poseidon) into circuit publics, contract storage, or off-chain deterministically-derived values. Renaming them invalidates the V5 circuit + Phase B ceremony + every existing fixture.</p><p>The frozen tags are documented in <strong><code>docs/superpowers/specs/2026-05-03-zkqes-rename-design.md</code> §3</strong> — keep them; never touch. Each occurrence in code carries a freeze comment pointing back at that spec section. If you&#39;re writing a new amendment that needs a new domain-separation tag, name it with a <code>zkqes-</code> prefix; existing tags stay frozen.</p><h2 id="domains" tabindex="-1">Domains <a class="header-anchor" href="#domains" aria-label="Permalink to &quot;Domains&quot;">​</a></h2><p>The public-facing surface uses three subdomains under <code>zkqes.org</code>. Locked 2026-05-03.</p><table tabindex="0"><thead><tr><th>Subdomain</th><th>Purpose</th><th>Lifecycle</th></tr></thead><tbody><tr><td><code>zkqes.org</code> (root)</td><td>Pre-ceremony hero + ceremony recruitment CTA + three contribution paths (snarkjs local / VPS / Fly launcher)</td><td>Live pre-recruitment; persists post-launch as the project landing</td></tr><tr><td><code>app.zkqes.org</code></td><td>The actual register flow — <code>/ua/registerV5</code> + <code>/account/rotate</code>. Hosts the SPA. End users come here only after Phase B ceremony completes + Sepolia E2E §9.4 green</td><td>Live post-ceremony</td></tr><tr><td><code>docs.zkqes.org</code></td><td>VitePress-rendered docs from the <code>docs/</code> tree — install instructions, specs, ceremony attestations, SDK reference, this BRAND.md</td><td>Live pre-recruitment</td></tr><tr><td><code>prove.zkqes.org</code></td><td>Ceremony coordinator (R2-backed status feed + manifest hosting)</td><td>Live post-DNS migration; bucket name <code>prove-zkqes-org</code></td></tr></tbody></table><p>Old <code>prove.identityescrow.org</code> host + <code>prove-identityescrow-org</code> R2 bucket remain frozen as a read-only mirror for V3/V4 historical artifacts; new ceremony rounds publish at <code>prove.zkqes.org</code>.</p><p>The split exists because the three audiences are distinct: ceremony contributors (zkqes.org root), end users registering with their QES (app.zkqes.org, post-launch), and developers / integrators / researchers (docs.zkqes.org). Surfacing all three on one page would mute the call-to-action that matters at the current lifecycle stage.</p><h2 id="defensive-registrations" tabindex="-1">Defensive registrations <a class="header-anchor" href="#defensive-registrations" aria-label="Permalink to &quot;Defensive registrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>Status</th><th>Action</th></tr></thead><tbody><tr><td><code>zkqes.org</code></td><td>Live, canonical</td><td>Keep — primary public domain</td></tr><tr><td><code>identityescrow.org</code></td><td>Held (never published a working public surface)</td><td>No 301 needed at present; can be added later if any traffic appears</td></tr><tr><td><code>alik-eth/zkqes</code> (GitHub)</td><td>Live</td><td>Repo (renamed 2026-05-03 from <code>identityescroworg</code>); GitHub auto-redirects the old URL</td></tr><tr><td><code>zkqes.com</code></td><td>Open call</td><td>Recommended defensive buy + 301 → <code>zkqes.org</code></td></tr><tr><td><code>@zkqes</code> (npm)</td><td>Open call — <strong>claim before first publish</strong></td><td>Defensive squat + protocol scope</td></tr><tr><td><code>@qkb</code> (npm)</td><td>Open call (no publishes ever)</td><td>No action — names are not used after the rename</td></tr></tbody></table><h2 id="when-this-document-changes" tabindex="-1">When this document changes <a class="header-anchor" href="#when-this-document-changes" aria-label="Permalink to &quot;When this document changes&quot;">​</a></h2><p>This brand collapse is intentionally robust to future edits — the ship surface is single-name, the protocol is single-name, the domain is single-name. If founder later decides to introduce a sub-brand (e.g., a separate name for an EVM-native variant or a fork), it should land as a new noun under the same project, not a re-litigation of the three-tier split.</p><p>Do not edit this document without founder sign-off.</p>',29)])])}const m=t(a,[["render",s]]);export{p as __pageData,m as default};
